For Go, the go-redis client is the standard:

```go
import "github.com/redis/go-redis/v9"

rdb := redis.NewClient(&redis.Options{
    Addr:     os.Getenv("REDIS_URL"),
    Password: os.Getenv("REDIS_PASSWORD"),
    DB:       0,
})
```

For your two use cases, use separate Redis databases or key prefixes:

**Caching permissions (DB 0, short TTL):**
```go
func cachePermissions(ctx context.Context, userID string, perms []string) error {
    key := fmt.Sprintf("perms:%s", userID)
    data, _ := json.Marshal(perms)
    return rdb.Set(ctx, key, data, 5*time.Minute).Err()
}

func getCachedPermissions(ctx context.Context, userID string) ([]string, error) {
    key := fmt.Sprintf("perms:%s", userID)
    data, err := rdb.Get(ctx, key).Bytes()
    if err == redis.Nil { return nil, nil } // cache miss
    if err != nil { return nil, err }
    var perms []string
    return perms, json.Unmarshal(data, &perms)
}
```

**Session management (DB 1, session TTL):**
```go
func createSession(ctx context.Context, sessionID string, data SessionData) error {
    key := fmt.Sprintf("session:%s", sessionID)
    encoded, _ := json.Marshal(data)
    return rdb.Set(ctx, key, encoded, 24*time.Hour).Err()
}
```

